import React, { useState, useEffect } from "react";

function RouteTable({ newRoute }) { // newRoute — сразу добавляем в таблицу
  const [routes, setRoutes] = useState([]);
  const [trains, setTrains] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5050/routes")
      .then(res => res.json())
      .then(setRoutes)
      .catch(console.error);

    fetch("http://localhost:5050/trains")
      .then(res => res.json())
      .then(setTrains)
      .catch(console.error);
  }, []);

  // если пришёл новый маршрут, добавляем его в состояние
  useEffect(() => {
    if (newRoute) setRoutes(prev => [...prev, newRoute]);
  }, [newRoute]);

  const getTrainName = (train_id) => {
    const train = trains.find(t => t.id === train_id);
    return train ? train.name : "Unknown";
  };

  if (!routes.length) return <p>Маршруты пока не добавлены</p>;

  return (
    <div>
      <h2>Маршруты</h2>
      <table border="1" cellPadding="5" style={{ borderCollapse: "collapse" }}>
        <thead>
          <tr>
            <th>ID</th>
            <th>Станция отправления</th>
            <th>Станция прибытия</th>
            <th>Поезд</th>
          </tr>
        </thead>
        <tbody>
          {routes.map(r => (
            <tr key={r.id}>
              <td>{r.id}</td>
              <td>{r.departure_station}</td>
              <td>{r.arrival_station}</td>
              <td>{getTrainName(r.train_id)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default RouteTable;
